// Second use_figma pass: ON_CLICK → NAVIGATE between Hi-Fi frames (after figma-hifi-build.js).
// File: Vizehelp — UX Blueprint · fileKey: DSCJffFtqgEbYHnNXt2AZJ

await figma.loadFontAsync({ family: 'Inter', style: 'Regular' });
await figma.loadFontAsync({ family: 'Inter', style: 'Semi Bold' });
await figma.loadFontAsync({ family: 'Inter', style: 'Bold' });

const protoTran = {
  type: 'SMART_ANIMATE',
  easing: { type: 'EASE_OUT' },
  duration: 0.28
};

async function wireNav(node, destId) {
  if (!node || !destId) return;
  await node.setReactionsAsync([
    {
      trigger: { type: 'ON_CLICK' },
      actions: [
        {
          type: 'NODE',
          destinationId: destId,
          navigation: 'NAVIGATE',
          transition: protoTran,
          resetScrollPosition: true
        }
      ]
    }
  ]);
}

function findDeep(root, predicate) {
  const out = [];
  if (predicate(root)) out.push(root);
  if ('children' in root) {
    for (const c of root.children) out.push(...findDeep(c, predicate));
  }
  return out;
}

function byName(root, nm) {
  return findDeep(root, (n) => n.name === nm)[0] || null;
}

const page = figma.root.children.find((p) => p.name === 'Prototype — Hi-Fi Desktop');
if (!page) {
  throw new Error('Page "Prototype — Hi-Fi Desktop" not found. Run figma-hifi-build.js first.');
}

await figma.setCurrentPageAsync(page);

function frameByTitle(title) {
  const f = page.children.find((n) => n.type === 'FRAME' && n.name === title);
  if (!f) throw new Error('Frame not found: ' + title);
  return f;
}

const scrHome = frameByTitle('SCR — Marketing / Home');
const scrSign = frameByTitle('SCR — Auth / Enterprise Signup');
const scrVer = frameByTitle('SCR — Auth / Verification');
const scrEnt = frameByTitle('SCR — Enterprise / Dashboard');
const scrAdm = frameByTitle('SCR — Super Admin / Dashboard');

const pairs = [
  ['proto-home-register-nav', scrSign.id],
  ['proto-home-register-hero', scrSign.id],
  ['proto-home-login', scrEnt.id],
  ['proto-sign-back', scrHome.id],
  ['proto-sign-exit', scrHome.id],
  ['proto-sign-continue', scrVer.id],
  ['proto-verify-dashboard', scrEnt.id],
  ['proto-ent-governance', scrAdm.id],
  ['proto-adm-enterprise', scrEnt.id]
];

const mutatedNodeIds = [];
for (const [hotspot, destId] of pairs) {
  const root =
    hotspot.startsWith('proto-home') ? scrHome : hotspot.startsWith('proto-sign') ? scrSign : hotspot.startsWith('proto-verify') ? scrVer : hotspot.startsWith('proto-ent') ? scrEnt : scrAdm;
  const node = byName(root, hotspot);
  if (!node) throw new Error('Hotspot not found: ' + hotspot);
  await wireNav(node, destId);
  mutatedNodeIds.push(node.id);
}

return {
  phase: 'prototype-wire',
  pageId: page.id,
  mutatedNodeIds,
  frameIds: [scrHome.id, scrSign.id, scrVer.id, scrEnt.id, scrAdm.id],
  prototypeFlow:
    'Home→Signup (Register) · Home→Dashboard (Login demo) · Signup→Home (Back/Exit) · Signup→Verification (Continue) · Verification→Dashboard (Approved demo) · Enterprise↔Super Admin (governance preview)'
};
